import hashlib

def passes_length_check(candidate: RawCandidate, min_words: int = 8) -> bool:
    return len(candidate.user_input.split()) >= min_words

RELEVANCE_JUDGE_PROMPT = """Does this user message plausibly belong to the stated intent category?

Task: {task_description}
Intent category: {intent}
User message: {user_input}

Answer yes or no only."""

def passes_relevance_check(
    candidate: RawCandidate,
    task_description: str,
    model: str = "claude-haiku-4-5-20251001",
) -> bool:
    msg = client.messages.create(
        model=model,
        max_tokens=4,
        messages=[{"role": "user", "content": RELEVANCE_JUDGE_PROMPT.format(
            task_description=task_description,
            intent=candidate.intent,
            user_input=candidate.user_input,
        )}],
    )
    return msg.content[0].text.strip().lower().startswith("y")

def dedup_by_prefix(candidates: list[RawCandidate], prefix_len: int = 40) -> list[RawCandidate]:
    """Remove near-duplicates that share the same opening characters."""
    seen: set[str] = set()
    result = []
    for c in candidates:
        key = c.user_input.strip().lower()[:prefix_len]
        if key not in seen:
            seen.add(key)
            result.append(c)
    return result

def filter_candidates(
    candidates: list[RawCandidate],
    task_description: str,
    model: str = "claude-haiku-4-5-20251001",
) -> list[RawCandidate]:
    passed = [c for c in candidates if passes_length_check(c)]
    passed = dedup_by_prefix(passed)
    # Relevance check is expensive — apply last
    passed = [
        c for c in passed
        if passes_relevance_check(c, task_description, model)
    ]
    return passed

LABEL_PROMPT = """You are labelling an evaluation case for an AI agent.

Agent task: {task_description}
Agent system prompt: {system_prompt}

User message: {user_input}

Write the key information that a correct agent response must include.
Be specific: name the fields, values, or actions that must appear.
Do not write the full response — just the required content.

Return JSON only:
{{
  "required_content": ["<item 1>", "<item 2>"],
  "check_type": "regex or rubric",
  "rubric_criteria": ["<criterion>"] 
}}"""

def label_candidate(
    candidate: RawCandidate,
    seed: SyntheticGenSeed,
    model: str = "claude-haiku-4-5-20251001",
) -> dict:
    msg = client.messages.create(
        model=model,
        max_tokens=256,
        messages=[{"role": "user", "content": LABEL_PROMPT.format(
            task_description=seed.task_description,
            system_prompt=seed.system_prompt,
            user_input=candidate.user_input,
        )}],
    )
    raw = msg.content[0].text
    m = re.search(r"\{.*\}", raw, re.DOTALL)
    if m:
        try:
            return json.loads(m.group())
        except json.JSONDecodeError:
            pass
    return {"required_content": [], "check_type": "rubric", "rubric_criteria": [candidate.expected_hint]}
